class Solution {
public:
    int longestSemiRepetitiveSubstring(string s) {
        int n = s.length();
        int max_len = 1;
        for (int i = 1; i < n; i++) {
            int count[10] = {0};
            for (int j = 0; j < n; j++) {
                if (s[j] == s[j + 1]) {
                    count[s[j]]++;
                } else {
                    count[s[j]]--;
                }
            }
            for (int k = 0; k < 10; k++) {
                max_len = max(max_len, count[k]);
            }
        }
        return max_len;
    }
};
```

